import * as React from 'react';
import type { DefaultSizeType } from '../util/size';
import type { RadioValue, RadioChangeEvent } from './interface';

export interface RadioGroupContextProps {
  onChange: (e: RadioChangeEvent) => void;
  value?: RadioValue;
  disabled?: boolean;
  name?: string;
  error?: boolean;
  registerBOT: (value: string | number | boolean) => void;
  unregisterBOT: (value: string | number | boolean) => void;
  size: DefaultSizeType;
}

export const RadioGroupContext = React.createContext<RadioGroupContextProps | null>(null);

export const RadioGroupContextProvider = RadioGroupContext.Provider;
